import{bQ as a,aL as t,u as i,G as e}from"./chunks/framework.D06dwy5q.js";const c=JSON.parse('{"title":"镜像安全","description":"","frontmatter":{},"headers":[],"relativePath":"09.容器化/11-镜像安全.md","filePath":"09.容器化/11-镜像安全.md","lastUpdated":null}'),n={name:"09.容器化/11-镜像安全.md"};function d(p,s,l,h,r,o){return t(),i("div",null,[...s[0]||(s[0]=[e(`<h1 id="镜像安全" tabindex="-1">镜像安全 <a class="header-anchor" href="#镜像安全" aria-label="Permalink to &quot;镜像安全&quot;">​</a></h1><p>镜像安全覆盖基础镜像来源、漏洞扫描、敏感信息、构建过程、签名、SBOM 和仓库权限。容器运行时的隔离不能弥补镜像本身的问题：镜像里带了高危漏洞、私钥、后门脚本，运行起来后风险已经进入环境。</p><p>镜像是 CI/CD 和 Kubernetes 的交付制品。一次发布最终落到集群里的往往不是代码仓库某个 commit，而是某个镜像 tag 或 digest。镜像安全做得清楚，后面排查“这个版本到底是什么构建出来的”会轻很多。</p><h2 id="一、基础镜像来源" tabindex="-1">一、基础镜像来源 <a class="header-anchor" href="#一、基础镜像来源" aria-label="Permalink to &quot;一、基础镜像来源&quot;">​</a></h2><p>基础镜像通常分三类：</p><table tabindex="0"><thead><tr><th>类型</th><th>说明</th></tr></thead><tbody><tr><td>官方镜像</td><td>Docker Hub 官方维护或语言社区维护</td></tr><tr><td>发行版镜像</td><td>Ubuntu、Debian、Alpine、Rocky 等基础系统</td></tr><tr><td>公司基础镜像</td><td>内部统一加固、统一 CA、统一时区和基础工具</td></tr></tbody></table><p>正式服务更适合用固定版本：</p><div class="language-dockerfile vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">dockerfile</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> python:3.12.4-slim-bookworm</span></span></code></pre></div><p><code>latest</code> 会随时间变化，构建结果不可追溯。<code>alpine</code> 镜像很小，但 musl libc 和 glibc 行为不同，某些 Python、Node.js、Java 原生依赖可能遇到兼容问题。镜像瘦身要和排错便利、兼容性一起权衡。</p><h2 id="二、漏洞扫描" tabindex="-1">二、漏洞扫描 <a class="header-anchor" href="#二、漏洞扫描" aria-label="Permalink to &quot;二、漏洞扫描&quot;">​</a></h2><p>常见扫描工具：</p><table tabindex="0"><thead><tr><th>工具</th><th>说明</th></tr></thead><tbody><tr><td>Trivy</td><td>常用镜像漏洞、配置、Secret、SBOM 扫描工具</td></tr><tr><td>Grype</td><td>Anchore 生态漏洞扫描</td></tr><tr><td>Harbor Scanner</td><td>Harbor 内置扫描入口，常接 Trivy</td></tr><tr><td>云厂商扫描</td><td>和云镜像仓库、准入策略集成</td></tr></tbody></table><p>Trivy 示例：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 扫描镜像里的系统包和语言依赖漏洞</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">trivy</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> image</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> registry.example.com/ops/web:1.0.0</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 只显示 HIGH 和 CRITICAL 级别</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">trivy</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> image</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --severity</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> HIGH,CRITICAL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> registry.example.com/ops/web:1.0.0</span></span></code></pre></div><p>漏洞扫描结果要结合实际暴露面判断。比如 Trivy 报出基础镜像里的 <code>libxml2</code> 高危漏洞，但这个镜像只跑一个不解析 XML 的内部批处理任务，修复优先级通常低于公网 API 镜像里的 Web 框架远程执行漏洞。反过来，如果漏洞组件就在对外入口路径上，访问日志里每天都有公网请求打到这个服务，就不能只因为“容器隔离”而放过。</p><h2 id="三、敏感信息" tabindex="-1">三、敏感信息 <a class="header-anchor" href="#三、敏感信息" aria-label="Permalink to &quot;三、敏感信息&quot;">​</a></h2><p>镜像层是可追溯的。Dockerfile 里 <code>COPY</code> 进去又删除的密钥，仍可能留在历史层里。</p><p>风险写法：</p><div class="language-dockerfile vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">dockerfile</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">COPY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> id_rsa /root/.ssh/id_rsa</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">RUN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> git clone git@example.com:ops/private-repo.git &amp;&amp; rm -f /root/.ssh/id_rsa</span></span></code></pre></div><p>更合适的方向是使用 BuildKit secret 或 SSH mount：</p><div class="language-dockerfile vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">dockerfile</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># syntax=docker/dockerfile:1.7</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">RUN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> --mount=type=ssh git clone git@example.com:ops/private-repo.git /src</span></span></code></pre></div><p>构建时传入：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 使用本机 SSH agent，不把私钥写入镜像层</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">DOCKER_BUILDKIT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --ssh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> default</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -t</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app:1.0</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span></span></code></pre></div><p><code>.env</code>、私钥、云 AK/SK、数据库密码、NPM token 都不应该进入镜像。<code>.dockerignore</code> 是第一道门槛。</p><h2 id="四、sbom" tabindex="-1">四、SBOM <a class="header-anchor" href="#四、sbom" aria-label="Permalink to &quot;四、SBOM&quot;">​</a></h2><p>SBOM（Software Bill of Materials）是软件物料清单，记录镜像里包含哪些系统包、语言依赖和版本。发生供应链漏洞时，SBOM 能快速回答“哪些镜像包含这个组件”。</p><p>生成 SBOM：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">trivy</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> image</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --format</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cyclonedx</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --output</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> web-sbom.json</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  registry.example.com/ops/web:1.0.0</span></span></code></pre></div><p>SBOM 可以作为 CI 产物保存，也可以推送到支持 OCI artifact 的仓库。Harbor、Trivy、Syft/Grype、Cosign 这些工具都能参与这条链路。</p><h2 id="五、签名和-digest" tabindex="-1">五、签名和 digest <a class="header-anchor" href="#五、签名和-digest" aria-label="Permalink to &quot;五、签名和 digest&quot;">​</a></h2><p>tag 是可变引用，digest 是内容地址。镜像 digest 形如：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>registry.example.com/ops/web@sha256:1b2c3d...</span></span></code></pre></div><p>部署系统记录 digest，可以确认运行的镜像内容没有被同名 tag 替换。签名工具常见 Cosign：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 给镜像签名，真实环境里通常接 KMS 或 OIDC 身份</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cosign</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sign</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> registry.example.com/ops/web:1.0.0</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 验证签名</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cosign</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> verify</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> registry.example.com/ops/web:1.0.0</span></span></code></pre></div><p>签名的价值在准入阶段更明显。Kubernetes 准入策略可以要求镜像来自内部仓库、通过扫描、带签名后才能运行。</p><h2 id="六、harbor-权限和保留" tabindex="-1">六、Harbor 权限和保留 <a class="header-anchor" href="#六、harbor-权限和保留" aria-label="Permalink to &quot;六、Harbor 权限和保留&quot;">​</a></h2><p>Harbor 里至少区分几个项目：</p><table tabindex="0"><thead><tr><th>项目</th><th>说明</th></tr></thead><tbody><tr><td><code>base</code></td><td>公司基础镜像</td></tr><tr><td><code>ops</code></td><td>运维平台和工具镜像</td></tr><tr><td><code>app</code></td><td>业务应用镜像</td></tr><tr><td><code>ci</code></td><td>临时构建和测试镜像</td></tr></tbody></table><p>CI/CD 推镜像使用 Robot Account，不使用个人管理员账号。正式镜像 tag 设置不可变，避免同一个 <code>1.0.0</code> 被重复覆盖。临时构建 tag 设置保留策略，避免仓库磁盘被短期构建撑满。</p><h2 id="七、上线前检查" tabindex="-1">七、上线前检查 <a class="header-anchor" href="#七、上线前检查" aria-label="Permalink to &quot;七、上线前检查&quot;">​</a></h2><table tabindex="0"><thead><tr><th>检查项</th><th>说明</th></tr></thead><tbody><tr><td>基础镜像</td><td>来源可信、版本固定、维护状态正常</td></tr><tr><td>构建上下文</td><td><code>.dockerignore</code> 排除 <code>.git</code>、缓存、密钥和本地配置</td></tr><tr><td>漏洞扫描</td><td>高危和严重漏洞有处理结论</td></tr><tr><td>敏感信息</td><td>镜像层里不含私钥、token、密码</td></tr><tr><td>用户权限</td><td>尽量非 root 运行，必要 capabilities 明确</td></tr><tr><td>标签和 digest</td><td>版本可追溯，正式 tag 不覆盖</td></tr><tr><td>签名 / SBOM</td><td>关键服务保留供应链证据</td></tr></tbody></table><p>镜像安全不是发布最后点一下扫描按钮。基础镜像选型、Dockerfile 写法、CI 构建凭据、Harbor 权限、Kubernetes 准入策略是一条链，断在哪一段都可能把风险带进运行环境。</p>`,42)])])}const g=a(n,[["render",d]]);export{c as __pageData,g as default};
